mapper.select:
SELECT p.id, p.profile_no, e.id as entry_id, COALESCE(NULLIF(e.employee_no, ''), p.profile_no) AS employee_no, p.name, p.mobile, p.email, p.gender, p.status, p.create_time, p.onboard_date, e.leave_date, p.job_level, p.company_years, CASE WHEN p.onboard_date IS NULL THEN NULL ELSE CONCAT( FLOOR(TIMESTAMPDIFF(MONTH, p.onboard_date, CURDATE()) / 12), '年', MOD(TIMESTAMPDIFF(MONTH, p.onboard_date, CURDATE()), 12), '月' ) END AS company_age, d.name as dept_name, CASE WHEN e.job_title IS NULL OR e.job_title = '' THEN post_rel.post_names ELSE e.job_title END AS job_title, e.extension, e.office_location, jl.level_name as job_level_name, wl.location_name as work_location_name, supervisor.name as direct_supervisor_name, e.work_status, e.employment_type, p.tenant_id, st.name as tenant_name FROM hr_employee_profile p LEFT JOIN hr_employee_entry e ON e.id = ( SELECT e2.id FROM hr_employee_entry e2 WHERE e2.profile_id = p.id AND e2.deleted = 0 ORDER BY CASE WHEN e2.work_status = 4 THEN 1 ELSE 0 END, e2.entry_date DESC, e2.id DESC LIMIT 1 ) LEFT JOIN system_users u_bind ON u_bind.id = COALESCE(e.user_id, p.user_id) AND u_bind.deleted = 0
AND u_bind.tenant_id = #{tenantId}
LEFT JOIN ( SELECT su.tenant_id, su.mobile, MAX(su.id) AS id, MAX(su.dept_id) AS dept_id FROM system_users su WHERE su.deleted = 0
AND su.tenant_id = #{tenantId}
AND su.mobile IS NOT NULL AND su.mobile != '' GROUP BY su.tenant_id, su.mobile ) u_mobile ON u_bind.id IS NULL AND p.mobile = u_mobile.mobile AND p.tenant_id = u_mobile.tenant_id LEFT JOIN system_dept d ON d.id = COALESCE(u_bind.dept_id, u_mobile.dept_id, e.dept_id) LEFT JOIN hr_job_level jl ON e.job_level_id = jl.id LEFT JOIN hr_location wl ON e.work_location_id = wl.id LEFT JOIN hr_employee_profile supervisor ON e.direct_supervisor_id = supervisor.id LEFT JOIN system_tenant st ON p.tenant_id = st.id LEFT JOIN ( SELECT up.user_id, GROUP_CONCAT(sp.name ORDER BY sp.sort SEPARATOR '/') AS post_names FROM system_user_post up JOIN system_post sp ON up.post_id = sp.id AND sp.tenant_id = up.tenant_id WHERE up.deleted = 0 AND sp.deleted = 0 GROUP BY up.user_id ) post_rel ON post_rel.user_id = COALESCE(u_bind.id, u_mobile.id, e.user_id, p.user_id)
p.deleted = 0
AND p.tenant_id = #{tenantId}
AND ( p.profile_no LIKE CONCAT('%', #{ew.employeeNo}, '%') OR e.employee_no LIKE CONCAT('%', #{ew.employeeNo}, '%') )
AND p.name LIKE CONCAT('%', #{ew.name}, '%')
AND p.mobile LIKE CONCAT('%', #{ew.mobile}, '%')
AND p.email LIKE CONCAT('%', #{ew.email}, '%')
AND p.gender = #{ew.gender}
AND COALESCE(u_bind.dept_id, u_mobile.dept_id, e.dept_id) IN
#{deptId}
AND COALESCE(u_bind.dept_id, u_mobile.dept_id, e.dept_id) = #{ew.deptId}
AND e.job_title LIKE CONCAT('%', #{ew.jobTitle}, '%')
AND p.status = #{ew.status}
AND p.onboard_date >= #{ew.onboardDateStart}
AND p.onboard_date <= #{ew.onboardDateEnd}
AND e.work_status = #{ew.workStatus}
AND (e.work_status IS NULL OR e.work_status <> #{ew.excludeWorkStatus})
AND e.employment_type = #{ew.employmentType}
ORDER BY p.create_time DESC

SELECT p.id, p.profile_no, e.id as entry_id, COALESCE(NULLIF(e.employee_no, ''), p.profile_no) AS employee_no, p.name, p.mobile, p.email, p.gender, p.status, p.id_number, p.birth_date, p.age, p.nationality, p.ethnicity, p.political_status, p.marital_status, p.hometown, p.address, p.emergency_contact, p.emergency_phone, p.emergency_relation, p.create_time, p.update_time, p.onboard_date, p.confirmation_date, p.job_level, p.company_years, p.father_birthday, p.mother_birthday, CASE WHEN p.onboard_date IS NULL THEN NULL ELSE CONCAT( FLOOR(TIMESTAMPDIFF(MONTH, p.onboard_date, CURDATE()) / 12), '年', MOD(TIMESTAMPDIFF(MONTH, p.onboard_date, CURDATE()), 12), '月' ) END AS company_age, COALESCE(u_bind.dept_id, u_mobile.dept_id, e.dept_id) as dept_id, d.name as dept_name, CASE WHEN e.job_title IS NULL OR e.job_title = '' THEN post_rel.post_names ELSE e.job_title END AS job_title, e.extension, e.office_location, jl.level_name as job_level_name, wl.location_name as work_location_name, e.direct_supervisor_id, supervisor.name as direct_supervisor_name, e.work_status, e.employment_type, e.probation_months, e.contract_type, e.contract_start_date, e.contract_end_date, e.leave_date, e.leave_reason, e.bank_name, e.bank_account, e.bank_branch, e.account_name, e.remark, edu.education, edu.school_name, edu.major, edu.graduation_date FROM hr_employee_profile p LEFT JOIN hr_employee_entry e ON e.id = ( SELECT e2.id FROM hr_employee_entry e2 WHERE e2.profile_id = p.id AND e2.deleted = 0 ORDER BY CASE WHEN e2.work_status = 4 THEN 1 ELSE 0 END, e2.entry_date DESC, e2.id DESC LIMIT 1 ) LEFT JOIN system_users u_bind ON u_bind.id = COALESCE(e.user_id, p.user_id) AND u_bind.deleted = 0
AND u_bind.tenant_id = #{tenantId}
LEFT JOIN ( SELECT su.tenant_id, su.mobile, MAX(su.id) AS id, MAX(su.dept_id) AS dept_id FROM system_users su WHERE su.deleted = 0
AND su.tenant_id = #{tenantId}
AND su.mobile IS NOT NULL AND su.mobile != '' GROUP BY su.tenant_id, su.mobile ) u_mobile ON u_bind.id IS NULL AND p.mobile = u_mobile.mobile AND p.tenant_id = u_mobile.tenant_id LEFT JOIN system_dept d ON d.id = COALESCE(u_bind.dept_id, u_mobile.dept_id, e.dept_id) LEFT JOIN hr_job_level jl ON e.job_level_id = jl.id LEFT JOIN hr_location wl ON e.work_location_id = wl.id LEFT JOIN hr_employee_profile supervisor ON e.direct_supervisor_id = supervisor.id LEFT JOIN ( SELECT up.user_id, GROUP_CONCAT(sp.name ORDER BY sp.sort SEPARATOR '/') AS post_names FROM system_user_post up JOIN system_post sp ON up.post_id = sp.id AND sp.tenant_id = up.tenant_id WHERE up.deleted = 0 AND sp.deleted = 0 GROUP BY up.user_id ) post_rel ON post_rel.user_id = COALESCE(u_bind.id, u_mobile.id, e.user_id, p.user_id) LEFT JOIN ( SELECT profile_id, education, school_name, major, graduation_date FROM hr_employee_education WHERE is_highest = 1 AND deleted = 0 ) edu ON p.id = edu.profile_id WHERE p.id = #{id}
AND p.tenant_id = #{tenantId}

SELECT COUNT(1) as total, IFNULL(SUM(flag_admin), 0) as admin, IFNULL(SUM(flag_admin_front), 0) as adminFront, IFNULL(SUM(flag_admin_logistics), 0) as adminLogistics, IFNULL(SUM(flag_hr), 0) as hr, IFNULL(SUM(flag_hr_recruit), 0) as hrRecruit, IFNULL(SUM(flag_hr_salary), 0) as hrSalary FROM ( SELECT p.id, MAX(CASE WHEN sp.name LIKE '%行政%' THEN 1 ELSE 0 END) AS flag_admin, MAX(CASE WHEN sp.name LIKE '%前台%' THEN 1 ELSE 0 END) AS flag_admin_front, MAX(CASE WHEN sp.name LIKE '%后勤%' THEN 1 ELSE 0 END) AS flag_admin_logistics, MAX( CASE WHEN sp.name LIKE '%人事%' OR sp.name LIKE '%人力%' OR sp.name LIKE '%HR%' OR LOWER(sp.code) LIKE '%hr%' THEN 1 ELSE 0 END ) AS flag_hr, MAX(CASE WHEN sp.name LIKE '%招聘%' OR sp.name LIKE '%招募%' THEN 1 ELSE 0 END) AS flag_hr_recruit, MAX(CASE WHEN sp.name LIKE '%薪酬%' OR sp.name LIKE '%薪资%' OR sp.name LIKE '%薪金%' THEN 1 ELSE 0 END) AS flag_hr_salary FROM hr_employee_profile p LEFT JOIN system_user_post sup ON sup.user_id = p.user_id AND sup.deleted = 0 AND sup.tenant_id = p.tenant_id LEFT JOIN system_post sp ON sp.id = sup.post_id AND sp.deleted = 0 AND sp.tenant_id = p.tenant_id WHERE p.deleted = 0
AND p.tenant_id = #{tenantId}
GROUP BY p.id ) t

SELECT SUM( CASE WHEN edu.education IS NOT NULL AND ( edu.education LIKE '%硕士%' OR edu.education LIKE '%博士%' OR edu.education LIKE '%研究生%' OR LOWER(edu.education) IN ('master', 'doctor', 'phd', 'postgraduate') ) THEN 1 ELSE 0 END ) as master, SUM( CASE WHEN edu.education IS NOT NULL AND ( edu.education LIKE '%本科%' OR LOWER(edu.education) IN ('bachelor', 'undergraduate') ) THEN 1 ELSE 0 END ) as bachelor, SUM(CASE WHEN edu_any.profile_id IS NOT NULL THEN 1 ELSE 0 END) as related FROM hr_employee_profile p LEFT JOIN ( SELECT profile_id, COALESCE(MAX(CASE WHEN is_highest = 1 THEN education END), MAX(education)) AS education FROM hr_employee_education WHERE deleted = 0
AND tenant_id = #{tenantId}
GROUP BY profile_id ) edu ON p.id = edu.profile_id LEFT JOIN ( SELECT DISTINCT profile_id FROM hr_employee_education WHERE deleted = 0
AND tenant_id = #{tenantId}
) edu_any ON p.id = edu_any.profile_id WHERE p.deleted = 0
AND p.tenant_id = #{tenantId}

SELECT sp.id AS post_id, sp.name AS post_name, COUNT(DISTINCT p.id) AS total FROM hr_employee_profile p LEFT JOIN hr_employee_entry e ON p.id = e.profile_id JOIN system_user_post sup ON sup.user_id = COALESCE(e.user_id, p.user_id) AND sup.deleted = 0 AND sup.tenant_id = p.tenant_id JOIN system_post sp ON sp.id = sup.post_id AND sp.deleted = 0 AND sp.tenant_id = p.tenant_id WHERE p.deleted = 0
AND p.tenant_id = #{tenantId}
GROUP BY sp.id, sp.name, sp.sort ORDER BY total DESC, sp.sort ASC, sp.id ASC
